"use strict";(self.webpackChunk_=self.webpackChunk_||[]).push([["1715"],{97340(n){n.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"platform-engineering-evolution","metadata":{"permalink":"/ai-sw-engineering/blog/platform-engineering-evolution","source":"@site/blog/2026-05-14-platform-engineering-evolution/index.md","title":"\uD50C\uB7AB\uD3FC \uC5D4\uC9C0\uB2C8\uC5B4\uB9C1\uC758 \uC9C4\uD654 \uB85C\uB4DC\uB9F5: \uB3C4\uAD6C\uC758 \uD30C\uD3B8\uD654\uC5D0\uC11C \uC5D0\uC774\uC804\uD2B8\uD615 \uD50C\uB7AB\uD3FC\uAE4C\uC9C0","description":"\uD50C\uB7AB\uD3FC \uC5D4\uC9C0\uB2C8\uC5B4\uB9C1\uC758 \uBBF8\uB798\uB294 \\"\uB3C4\uAD6C\uB97C \uB354 \uB9CE\uC774 \uBD99\uC774\uB294 \uAC83\\"\uC774 \uC544\uB2C8\uB77C, \uAC1C\uBC1C\uC790\uAC00 \uBCF5\uC7A1\uD568\uC744 \uC9C1\uC811 \uB2E4\uB8E8\uC9C0 \uC54A\uB3C4\uB85D \uCD94\uC0C1\uD654\uD558\uB294 \uAC83\uC5D0 \uC788\uB2E4. \uD234 \uBAA8\uC74C \u2192 IDP \u2192 AI-\uBCF4\uAC15 \u2192 \uC5D0\uC774\uC804\uD2B8\uD615, 4\uB2E8\uACC4 \uC9C4\uD654 \uB85C\uB4DC\uB9F5\uC744 \uC815\uB9AC\uD588\uB2E4.","date":"2026-05-14T00:00:00.000Z","tags":[{"inline":false,"label":"\uD50C\uB7AB\uD3FC \uC5D4\uC9C0\uB2C8\uC5B4\uB9C1","permalink":"/ai-sw-engineering/blog/tags/platform-engineering","description":"\uB0B4\uBD80 \uAC1C\uBC1C\uC790 \uD50C\uB7AB\uD3FC \uBC0F \uD50C\uB7AB\uD3FC \uC5D4\uC9C0\uB2C8\uC5B4\uB9C1 \uC804\uB7B5"},{"inline":false,"label":"DevOps","permalink":"/ai-sw-engineering/blog/tags/devops","description":"DevOps \uBB38\uD654, \uB3C4\uAD6C, \uC790\uB3D9\uD654"},{"inline":false,"label":"\uAC1C\uBC1C\uC790 \uACBD\uD5D8","permalink":"/ai-sw-engineering/blog/tags/developer-experience","description":"\uAC1C\uBC1C\uC790 \uC0DD\uC0B0\uC131\uACFC \uACBD\uD5D8 \uAC1C\uC120"},{"inline":false,"label":"AI \uC5D0\uC774\uC804\uD2B8","permalink":"/ai-sw-engineering/blog/tags/ai-agent","description":"AI \uC5D0\uC774\uC804\uD2B8 \uC124\uACC4 \uBC0F \uC6CC\uD06C\uD50C\uB85C\uC6B0"},{"inline":false,"label":"\uC0DD\uC0B0\uC131","permalink":"/ai-sw-engineering/blog/tags/productivity","description":"\uC5C5\uBB34 \uC0DD\uC0B0\uC131 \uD5A5\uC0C1 \uB3C4\uAD6C\uC640 \uBC29\uBC95"}],"readingTime":3.02,"hasTruncateMarker":true,"authors":[{"name":"jeonck","title":"SW Engineer","url":"https://github.com/jeonck","page":{"permalink":"/ai-sw-engineering/blog/authors/jeonck"},"imageURL":"https://github.com/jeonck.png","key":"jeonck"}],"frontMatter":{"slug":"platform-engineering-evolution","title":"\uD50C\uB7AB\uD3FC \uC5D4\uC9C0\uB2C8\uC5B4\uB9C1\uC758 \uC9C4\uD654 \uB85C\uB4DC\uB9F5: \uB3C4\uAD6C\uC758 \uD30C\uD3B8\uD654\uC5D0\uC11C \uC5D0\uC774\uC804\uD2B8\uD615 \uD50C\uB7AB\uD3FC\uAE4C\uC9C0","authors":["jeonck"],"tags":["platform-engineering","devops","developer-experience","ai-agent","productivity"]},"unlisted":false,"nextItem":{"title":"8\uBA85 AI \uC5D0\uC774\uC804\uD2B8\uD300\uC73C\uB85C \uC5C5\uBB34 \uB9AC\uC11C\uCE58 10\uBD84 \uC548\uC5D0 \uB05D\uB0B4\uAE30","permalink":"/ai-sw-engineering/blog/8-agent-research-team"}},"content":"\uD50C\uB7AB\uD3FC \uC5D4\uC9C0\uB2C8\uC5B4\uB9C1\uC758 \uBBF8\uB798\uB294 \\"\uB3C4\uAD6C\uB97C \uB354 \uB9CE\uC774 \uBD99\uC774\uB294 \uAC83\\"\uC774 \uC544\uB2C8\uB77C, \uAC1C\uBC1C\uC790\uAC00 \uBCF5\uC7A1\uD568\uC744 \uC9C1\uC811 \uB2E4\uB8E8\uC9C0 \uC54A\uB3C4\uB85D \uCD94\uC0C1\uD654\uD558\uB294 \uAC83\uC5D0 \uC788\uB2E4. \uD234 \uBAA8\uC74C \u2192 IDP \u2192 AI-\uBCF4\uAC15 \u2192 \uC5D0\uC774\uC804\uD2B8\uD615, 4\uB2E8\uACC4 \uC9C4\uD654 \uB85C\uB4DC\uB9F5\uC744 \uC815\uB9AC\uD588\uB2E4.\\n\\n{/* truncate */}\\n\\n## \uBC30\uACBD: \uC65C \uC9C0\uAE08 \uD50C\uB7AB\uD3FC \uC5D4\uC9C0\uB2C8\uC5B4\uB9C1\uC778\uAC00\\n\\n\uD604\uB300\uC758 \uC18C\uD504\uD2B8\uC6E8\uC5B4 \uAC1C\uBC1C \uD658\uACBD\uC740 \uD074\uB77C\uC6B0\uB4DC \uB124\uC774\uD2F0\uBE0C \uC544\uD0A4\uD14D\uCC98\uC758 \uD655\uC0B0\uC73C\uB85C \uC778\uD574 \uBCF5\uC7A1\uC131\uC774 \uADF9\uB3C4\uB85C \uB192\uC544\uC84C\uB2E4. \uAC1C\uBC1C\uC790\uB4E4\uC740 \uBE44\uC988\uB2C8\uC2A4 \uB85C\uC9C1 \uAD6C\uD604\uBCF4\uB2E4 \uC778\uD504\uB77C \uC124\uC815, \uBCF4\uC548 \uC2A4\uCE94, CI/CD \uD30C\uC774\uD504\uB77C\uC778 \uAD00\uB9AC \uB4F1 \uBD80\uC218\uC801\uC778 \uC791\uC5C5\uC5D0 \uB354 \uB9CE\uC740 \uC2DC\uAC04\uC744 \uD560\uC560\uD558\uAC8C \uB418\uC5C8\uB2E4.\\n\\n\uC774\uB7EC\uD55C **\uC778\uC9C0 \uBD80\uD558(Cognitive Load)** \uC758 \uC99D\uAC00\uB294 \uC0DD\uC0B0\uC131 \uC800\uD558\uC640 \uC6B4\uC601 \uC624\uB958\uB85C \uC774\uC5B4\uC9C0\uBA70, \uAE30\uC5C5 \uC131\uC7A5\uC758 \uBC1C\uBAA9\uC744 \uC7A1\uB294 \uC8FC\uC694 \uC6D0\uC778\uC774 \uB418\uACE0 \uC788\uB2E4.\\n\\n---\\n\\n## 4\uB2E8\uACC4 \uC9C4\uD654 \uBAA8\uB378\\n\\n![\uD50C\uB7AB\uD3FC \uC5D4\uC9C0\uB2C8\uC5B4\uB9C1 \uC9C4\uD654 \uB85C\uB4DC\uB9F5](../images/platform-eng.png)\\n\\n\uD30C\uD3B8\uD654\uB41C \uB3C4\uAD6C \uBAA8\uC74C\uC5D0\uC11C \uC2DC\uC791\uD574 \uC758\uB3C4 \uAE30\uBC18\uC758 \uC790\uC728 \uC2E4\uD589\uC774 \uAC00\uB2A5\uD55C \uC5D0\uC774\uC804\uD2B8\uD615 \uD50C\uB7AB\uD3FC\uC73C\uB85C \uB098\uC544\uAC00\uB294 4\uB2E8\uACC4 \uC9C4\uD654 \uACFC\uC815\uC774\uB2E4.\\n\\n### 1\uB2E8\uACC4 \u2014 \uD234 \uBAA8\uC74C: \uBD84\uC0B0\uACFC \uC0AC\uC77C\uB85C\\n\\nCI/CD, IaC, Kubernetes, \uBCF4\uC548 \uC2A4\uCE90\uB108, \uAD00\uCE21\uC131 \uB3C4\uAD6C\uAC00 \uAC01\uAC01 \uD769\uC5B4\uC838 \uC788\uB2E4. \uAC1C\uBC1C\uC790\uB294 \\"\uBE60\uB974\uAC8C \uB9CC\uB4E4\uAE30\\"\uBCF4\uB2E4 **\\"\uC5B4\uB5A4 \uB3C4\uAD6C\uB97C \uC5B4\uB5A4 \uC21C\uC11C\uB85C \uC368\uC57C \uD558\uC9C0?\\"** \uB97C \uBA3C\uC800 \uACE0\uBBFC\uD558\uAC8C \uB41C\uB2E4.\\n\\n\uBB38\uC81C\uC758 \uBCF8\uC9C8\uC740 \uAE30\uB2A5 \uAC1C\uBC1C\uBCF4\uB2E4 \uC778\uC9C0 \uBD80\uD558\uAC00 \uCEE4\uC9C4\uB2E4\uB294 \uC810\uC774\uB2E4. \uC0AC\uC77C\uB85C\uD654\uB41C \uAD6C\uC870\uB85C \uC778\uD574 \uAC70\uBC84\uB10C\uC2A4 \uC0AC\uAC01\uC9C0\uB300\uB3C4 \uBC1C\uC0DD\uD55C\uB2E4.\\n\\n### 2\uB2E8\uACC4 \u2014 IDP: \uB0B4\uBD80 \uAC1C\uBC1C\uC790 \uD50C\uB7AB\uD3FC\\n\\n\uD3EC\uD138, \uC11C\uBE44\uC2A4 \uCE74\uD0C8\uB85C\uADF8, \uD15C\uD50C\uB9BF, \uACE8\uB4E0 \uD328\uC2A4, \uC140\uD504\uC11C\uBE44\uC2A4 API\uAC00 \uD558\uB098\uC758 \uACBD\uD5D8\uC73C\uB85C \uBB36\uC778\uB2E4. \uAC1C\uBC1C\uC790\uB294 \\"\uC11C\uBC84/\uD074\uB7EC\uC2A4\uD130\uB97C \uC5B4\uB5BB\uAC8C \uB9CC\uB4E4\uAE4C?\\"\uBCF4\uB2E4 **\\"\uC0C8 \uC11C\uBE44\uC2A4 \uD558\uB098 \uC2DC\uC791\\"** \uAC19\uC740 \uC81C\uD488\uD615 UX\uB97C \uBC1B\uAC8C \uB41C\uB2E4.\\n\\n\uD50C\uB7AB\uD3FC \uD300\uC740 \uC6B4\uC601\uD300\uC774 \uC544\uB2C8\uB77C **\uB0B4\uBD80 \uC81C\uD488 \uD300\uCC98\uB7FC \uC6C0\uC9C1\uC774\uAC8C \uB41C\uB2E4.** \uD45C\uC900\uD654\uB41C \'\uACE8\uB4E0 \uD328\uC2A4\'\uB97C \uD1B5\uD574 \uAC1C\uBC1C \uACBD\uD5D8\uC744 \uC77C\uC6D0\uD654\uD558\uB294 \uAC83\uC774 \uD575\uC2EC\uC774\uB2E4.\\n\\n### 3\uB2E8\uACC4 \u2014 AI-\uBCF4\uAC15 \uD50C\uB7AB\uD3FC: \uCF54\uD30C\uC77C\uB7FF\uC758 \uB4F1\uC7A5\\n\\nAI\uAC00 \uC11C\uBE44\uC2A4 \uC2A4\uCE90\uD3F4\uB529, \uC7A5\uC560 \uC6D0\uC778 \uD0D0\uC0C9, \uB85C\uADF8 \uC694\uC57D, \uBE44\uC6A9 \uCD5C\uC801\uD654, \uC815\uCC45 \uC704\uBC18 \uD0D0\uC9C0\uAE4C\uC9C0 \uBCF4\uC870\uD55C\uB2E4. \uD50C\uB7AB\uD3FC\uC740 \uBB38\uC11C \uC800\uC7A5\uC18C\uAC00 \uC544\uB2C8\uB77C, **\uC9C8\uBB38\uD558\uBA74 \uC2E4\uD589 \uAC00\uB2A5\uD55C \uCD94\uCC9C\uC744 \uC8FC\uB294 \uC778\uD130\uD398\uC774\uC2A4** \uB85C \uBC14\uB010\uB2E4.\\n\\n\uAC1C\uBC1C\uC790\uB294 YAML\uC744 \uC678\uC6B0\uAE30\uBCF4\uB2E4 **\\"\uC774 \uC11C\uBE44\uC2A4\uC5D0 \uD45C\uC900 \uBC30\uD3EC \uD30C\uC774\uD504\uB77C\uC778 \uBD99\uC5EC\uC918\\"** \uAC19\uC740 \uC694\uCCAD\uC744 \uD558\uAC8C \uB41C\uB2E4.\\n\\n### 4\uB2E8\uACC4 \u2014 \uC5D0\uC774\uC804\uD2B8\uD615 \uD50C\uB7AB\uD3FC: \uC758\uB3C4 \uAE30\uBC18 \uC790\uC728 \uC2E4\uD589\\n\\n\uC0AC\uC6A9\uC790\uB294 \uC790\uC5F0\uC5B4\uB85C \uC758\uB3C4\uB97C \uB9D0\uD558\uACE0, \uD50C\uB7AB\uD3FC \uC5D0\uC774\uC804\uD2B8\uAC00 \uBC30\uD3EC/\uAD8C\uD55C/\uD14C\uC2A4\uD2B8/\uC815\uCC45/AI \uD30C\uC774\uD504\uB77C\uC778\uAE4C\uC9C0 \uC870\uD569\uD55C\uB2E4.\\n\\n> \\"\uACB0\uC81C \uC11C\uBE44\uC2A4\uB97C \uAE00\uB85C\uBC8C\uB85C \uD655\uC7A5\uD558\uACE0, \uBCF4\uC548 \uADDC\uC815\uC744 \uC900\uC218\uD558\uBA70 \uBE44\uC6A9\uC744 \uCD5C\uC801\uD654\uD574\uC918.\\"\\n\\n\uD50C\uB7AB\uD3FC \uC5D0\uC774\uC804\uD2B8 \uC624\uCF00\uC2A4\uD2B8\uB808\uC774\uD130\uB294 \uC774 \uC758\uB3C4\uB97C \uBD84\uC11D\uD558\uC5EC \uC778\uD504\uB77C, \uC560\uD50C\uB9AC\uCF00\uC774\uC158, AI/ML \uD30C\uC774\uD504\uB77C\uC778\uC744 \uAC00\uB85C\uC9C0\uB974\uB294 \uC2E4\uD589 \uACC4\uD68D\uC744 \uC218\uB9BD\uD558\uACE0 \uC790\uC728\uC801\uC73C\uB85C \uC218\uD589\uD55C\uB2E4.\\n\\n\uB2E8, \uC644\uC804 \uC790\uC728\uBCF4\uB2E4 \uC911\uC694\uD55C \uAC83\uC740 **\uAC10\uC0AC \uAC00\uB2A5\uC131, \uC2B9\uC778 \uD750\uB984, \uC815\uCC45 \uD1B5\uC81C, \uB864\uBC31 \uAC00\uB2A5\uC131** \uC774\uB2E4.\\n\\n---\\n\\n## \uD50C\uB7AB\uD3FC\uC758 \uB3D9\uC791 \uC6D0\uB9AC: \uAC70\uBC84\uB10C\uC2A4 \uAC00\uB4DC\uB808\uC77C\\n\\n\uD50C\uB7AB\uD3FC\uC758 \uBAA8\uB4E0 \uB2E8\uACC4 \uC0C1\uB2E8\uC5D0\uB294 **\uC815\uCC45 \uAD00\uB9AC, \uC2E0\uC6D0 \uC811\uADFC \uC81C\uC5B4, \uCDE8\uC57D\uC810 \uAD00\uB9AC** \uB4F1 \'\uAC70\uBC84\uB10C\uC2A4 \uAC00\uB4DC\uB808\uC77C\'\uC774 \uBC30\uCE58\uB418\uC5B4 \uC788\uB2E4. \uAC1C\uBC1C\uC790\uAC00 \uC790\uC720\uB86D\uAC8C \uD50C\uB7AB\uD3FC\uC744 \uC0AC\uC6A9\uD558\uB418, \uC870\uC9C1\uC758 \uBCF4\uC548 \uAE30\uC900\uC744 \uBC97\uC5B4\uB098\uC9C0 \uC54A\uB3C4\uB85D \uAC15\uC81C\uD558\uB294 \uAD6C\uC870\uB2E4.\\n\\n\uBCF4\uC548, \uC815\uCC45, \uCEF4\uD50C\uB77C\uC774\uC5B8\uC2A4\uAC00 \uC0AC\uD6C4 \uC810\uAC80\uC774 \uC544\uB2C8\uB77C **\uC0AC\uC804 \uB0B4\uC7A5** \uB418\uB294 \uAC83\uC774 \uD575\uC2EC\uC774\uB2E4.\\n\\n---\\n\\n## \uC2E4\uC81C \uD65C\uC6A9 \uC2DC\uB098\uB9AC\uC624\\n\\n| \uC2DC\uB098\uB9AC\uC624 | \uB0B4\uC6A9 |\\n|---------|------|\\n| **\uAC1C\uBC1C \uC0DD\uC0B0\uC131** | \uD45C\uC900\uD654\uB41C \uD15C\uD50C\uB9BF \uCE74\uD0C8\uB85C\uADF8\uB97C \uD1B5\uD574 \uC778\uD504\uB77C\uC640 \uD30C\uC774\uD504\uB77C\uC778\uC744 \uB2E8 \uBA87 \uBC88\uC758 \uD074\uB9AD\uC73C\uB85C \uD504\uB85C\uBE44\uC800\uB2DD |\\n| **AI/ML \uC6CC\uD06C\uD50C\uB85C\uC6B0** | \uB370\uC774\uD130 \uC900\uBE44\uBD80\uD130 \uD559\uC2B5, \uD3C9\uAC00, \uBC30\uD3EC\uAE4C\uC9C0 \uC774\uC5B4\uC9C0\uB294 \uC5D4\uB4DC\uD22C\uC5D4\uB4DC \uD30C\uC774\uD504\uB77C\uC778 \uC790\uB3D9\uD654 |\\n| **\uC9C0\uB2A5\uD615 \uC6B4\uC601** | \uCF54\uD30C\uC77C\uB7FF\uC774 \uB85C\uADF8\uC640 \uD2B8\uB808\uC774\uC2A4\uB97C \uBD84\uC11D\uD558\uC5EC \uADFC\uBCF8 \uC6D0\uC778\uC744 \uC9C4\uB2E8\uD558\uACE0 \uD574\uACB0\uCC45\uC744 \uC81C\uC548 |\\n| **\uBE44\uC6A9 \uBC0F \uBAA8\uB378 \uD3C9\uAC00** | \uD074\uB77C\uC6B0\uB4DC \uBE44\uC6A9 \uB9AC\uD3EC\uD2B8\uC640 \uBAA8\uB378\uC758 \uC548\uC804\uC131/\uD3B8\uD5A5\uC131 \uD3C9\uAC00\uB97C \uC790\uB3D9 \uC218\uD589 |\\n\\n---\\n\\n## \uBB34\uC5C7\uC774 \uB2EC\uB77C\uC9C0\uB098: 5\uAC00\uC9C0 \uC804\uD658\uC810\\n\\n### 1. Self-service\uAC00 \uAE30\uBCF8\uAC12\\n\\n\uD2F0\uCF13 \uAE30\uBC18 \uC694\uCCAD \u2192 \uD3EC\uD138/CLI/API \uAE30\uBC18 \uC989\uC2DC \uC2E4\uD589\uC73C\uB85C \uC804\uD658\uB41C\uB2E4.\\n\\n### 2. Golden path\uAC00 \uD45C\uC900\\n\\n\\"\uC790\uC720\uB86D\uAC8C \uB2E4 \uD558\uC138\uC694\\"\uBCF4\uB2E4 **\\"\uAC00\uC7A5 \uC548\uC804\uD558\uACE0 \uBE60\uB978 \uAE30\uBCF8 \uACBD\uB85C\\"** \uB97C \uC81C\uACF5\uD558\uB294 \uBC29\uC2DD\uC73C\uB85C \uBC14\uB010\uB2E4.\\n\\n### 3. Guardrails\uAC00 \uD50C\uB7AB\uD3FC \uC548\uC73C\uB85C\\n\\n\uBCF4\uC548, \uC815\uCC45, \uCEF4\uD50C\uB77C\uC774\uC5B8\uC2A4\uAC00 \uC0AC\uD6C4 \uC810\uAC80\uC774 \uC544\uB2C8\uB77C \uC0AC\uC804 \uB0B4\uC7A5\uB41C\uB2E4.\\n\\n### 4. AI workload\uAE4C\uC9C0 \uD50C\uB7AB\uD3FC \uBC94\uC704\uAC00 \uD655\uC7A5\\n\\n\uC571 \uD50C\uB7AB\uD3FC + \uB370\uC774\uD130/\uBAA8\uB378/\uC5D0\uC774\uC804\uD2B8 \uC6B4\uC601 \uD50C\uB7AB\uD3FC\uC758 \uACBD\uACC4\uAC00 \uD569\uCCD0\uC9C4\uB2E4.\\n\\n### 5. Platform team\uC758 \uC5ED\uD560\uC774 \uC81C\uD488\uD654\\n\\n\uB0B4\uBD80 \uACE0\uAC1D\uC740 \uAC1C\uBC1C\uC790, \uB370\uC774\uD130\uD300, AI\uD300\uC774\uB2E4. \uC131\uACF5 \uC9C0\uD45C\uB3C4 **uptime\uBCF4\uB2E4 \uAC1C\uBC1C \uB9AC\uB4DC\uD0C0\uC784, \uCC44\uD0DD\uB960, \uC7AC\uC0AC\uC6A9\uB960, \uC778\uC9C0 \uBD80\uD558 \uAC10\uC18C** \uB85C \uC774\uB3D9\uD55C\uB2E4.\\n\\n---\\n\\n## \uAE30\uB300\uD6A8\uACFC\\n\\n| \uAC00\uCE58 | \uB0B4\uC6A9 |\\n|------|------|\\n| **\uC778\uC9C0 \uBD80\uD558 \uAC10\uC18C** | \uBCF5\uC7A1\uD55C \uB3C4\uAD6C \uCCB4\uC778\uC744 \uCD94\uC0C1\uD654\uD558\uC5EC \uAC1C\uBC1C\uC790\uAC00 \uD575\uC2EC \uAC00\uCE58 \uCC3D\uCD9C\uC5D0 \uC9D1\uC911 |\\n| **\uB354 \uBE60\uB978 \uC804\uB2EC(Velocity)** | \uC140\uD504\uC11C\uBE44\uC2A4\uC640 \uC790\uB3D9\uD654\uB97C \uD1B5\uD574 \uB9B4\uB9AC\uC988 \uC18D\uB3C4 \uD601\uC2E0 |\\n| **\uB192\uC740 \uC2E0\uB8B0\uC131** | \uC815\uCC45 \uAE30\uBC18 \uAC00\uB4DC\uB808\uC77C \uB0B4\uC7A5\uC73C\uB85C \uD734\uBA3C \uC5D0\uB7EC \uBC29\uC9C0, \uC2DC\uC2A4\uD15C \uC548\uC815\uC131 \uAC15\uD654 |\\n| **\uAC10\uC0AC \uAC00\uB2A5\uC131(Auditability)** | \uBAA8\uB4E0 \uBCC0\uACBD \uC0AC\uD56D\uC774 \uC77C\uAD00\uB41C \uB85C\uAE45\uACFC \uC99D\uC801 \uC790\uB8CC\uB85C \uAD00\uB9AC\uB418\uC5B4 \uCEF4\uD50C\uB77C\uC774\uC5B8\uC2A4 \uC900\uC218 \uC6A9\uC774 |\\n| **AI/ML \uC900\uBE44 \uC644\uB8CC** | \uB370\uC774\uD130\uBD80\uD130 \uBC30\uD3EC\uAE4C\uC9C0 \uC9C0\uC6D0\uD558\uB294 \uC778\uD504\uB77C\uB85C \uCD5C\uC2E0 AI \uAE30\uC220 \uB3C4\uC785 \uC7A5\uBCBD \uC81C\uAC70 |\\n\\n---\\n\\n## \uACB0\uB860: \uD55C \uBB38\uC7A5\uC73C\uB85C\\n\\n\uD50C\uB7AB\uD3FC \uC5D4\uC9C0\uB2C8\uC5B4\uB9C1\uC758 \uBBF8\uB798\uB294 \\"\uBCF5\uC7A1\uD55C \uAE30\uC220 \uC2A4\uD0DD\uC744 \uC798 \uC6B4\uC601\uD558\uB294 \uB2A5\uB825\\"\uBCF4\uB2E4, **\uAC1C\uBC1C\uC790\uC640 AI \uC5D0\uC774\uC804\uD2B8\uAC00 \uC548\uC804\uD558\uAC8C \uBE60\uB974\uAC8C \uC77C\uD558\uB3C4\uB85D \\"\uC88B\uC740 \uAE30\uBCF8 \uACBD\uB85C\uB97C \uC81C\uD488\uCC98\uB7FC \uC81C\uACF5\uD558\uB294 \uB2A5\uB825\\"** \uC5D0 \uB2EC\uB824 \uC788\uB2E4."},{"id":"8-agent-research-team","metadata":{"permalink":"/ai-sw-engineering/blog/8-agent-research-team","source":"@site/blog/2026-05-08-8-agent-research-team/index.md","title":"8\uBA85 AI \uC5D0\uC774\uC804\uD2B8\uD300\uC73C\uB85C \uC5C5\uBB34 \uB9AC\uC11C\uCE58 10\uBD84 \uC548\uC5D0 \uB05D\uB0B4\uAE30","description":"\uCC57\uBD07 \uD55C \uBA85\uC5D0\uAC8C \uB2E4 \uB9E1\uAE30\uB294 \uB9AC\uC11C\uCE58\uB294 \uC65C \uC2E4\uD328\uD558\uB294\uAC00. 40\uBD84\uC9DC\uB9AC \uB9AC\uC11C\uCE58\uB97C 10\uBD84\uC73C\uB85C \uB2E8\uCD95\uD55C 8\uBA85 \uC5D0\uC774\uC804\uD2B8\uD300 \uC6CC\uD06C\uD50C\uB85C\uC6B0 \uC2A4\uD0AC\uC744 Claude Code \uC2A4\uD0AC\uB85C \uAD6C\uD604\uD558\uACE0, AI \uAD11\uD1B5\uC2E0 \uAE30\uC220 \uB9AC\uC11C\uCE58\uB85C \uC2E4\uC804 \uAC80\uC99D\uD588\uB2E4.","date":"2026-05-08T00:00:00.000Z","tags":[{"inline":false,"label":"AI \uC5D0\uC774\uC804\uD2B8","permalink":"/ai-sw-engineering/blog/tags/ai-agent","description":"AI \uC5D0\uC774\uC804\uD2B8 \uC124\uACC4 \uBC0F \uC6CC\uD06C\uD50C\uB85C\uC6B0"},{"inline":false,"label":"\uC2A4\uD0AC","permalink":"/ai-sw-engineering/blog/tags/skill","description":"Claude Code \uC2A4\uD0AC \uC81C\uC791"},{"inline":false,"label":"\uB9AC\uC11C\uCE58","permalink":"/ai-sw-engineering/blog/tags/research","description":"AI \uAE30\uBC18 \uB9AC\uC11C\uCE58 \uBC29\uBC95\uB860"},{"inline":false,"label":"\uC0DD\uC0B0\uC131","permalink":"/ai-sw-engineering/blog/tags/productivity","description":"\uC5C5\uBB34 \uC0DD\uC0B0\uC131 \uD5A5\uC0C1 \uB3C4\uAD6C\uC640 \uBC29\uBC95"}],"readingTime":5.16,"hasTruncateMarker":true,"authors":[{"name":"jeonck","title":"SW Engineer","url":"https://github.com/jeonck","page":{"permalink":"/ai-sw-engineering/blog/authors/jeonck"},"imageURL":"https://github.com/jeonck.png","key":"jeonck"}],"frontMatter":{"slug":"8-agent-research-team","title":"8\uBA85 AI \uC5D0\uC774\uC804\uD2B8\uD300\uC73C\uB85C \uC5C5\uBB34 \uB9AC\uC11C\uCE58 10\uBD84 \uC548\uC5D0 \uB05D\uB0B4\uAE30","authors":["jeonck"],"tags":["ai-agent","skill","research","productivity"]},"unlisted":false,"prevItem":{"title":"\uD50C\uB7AB\uD3FC \uC5D4\uC9C0\uB2C8\uC5B4\uB9C1\uC758 \uC9C4\uD654 \uB85C\uB4DC\uB9F5: \uB3C4\uAD6C\uC758 \uD30C\uD3B8\uD654\uC5D0\uC11C \uC5D0\uC774\uC804\uD2B8\uD615 \uD50C\uB7AB\uD3FC\uAE4C\uC9C0","permalink":"/ai-sw-engineering/blog/platform-engineering-evolution"},"nextItem":{"title":"Claude Code \uC2A4\uD0AC \uB9CC\uB4E4\uAE30 \u2014 8\uBA85 AI \uC5D0\uC774\uC804\uD2B8 \uB9AC\uC11C\uCE58\uD300 \uC2E4\uC804 \uAD6C\uCD95","permalink":"/ai-sw-engineering/blog/build-research-agent-skill"}},"content":"\uCC57\uBD07 \uD55C \uBA85\uC5D0\uAC8C \uB2E4 \uB9E1\uAE30\uB294 \uB9AC\uC11C\uCE58\uB294 \uC65C \uC2E4\uD328\uD558\uB294\uAC00. 40\uBD84\uC9DC\uB9AC \uB9AC\uC11C\uCE58\uB97C 10\uBD84\uC73C\uB85C \uB2E8\uCD95\uD55C **8\uBA85 \uC5D0\uC774\uC804\uD2B8\uD300 \uC6CC\uD06C\uD50C\uB85C\uC6B0** \uC2A4\uD0AC\uC744 Claude Code \uC2A4\uD0AC\uB85C \uAD6C\uD604\uD558\uACE0, AI \uAD11\uD1B5\uC2E0 \uAE30\uC220 \uB9AC\uC11C\uCE58\uB85C \uC2E4\uC804 \uAC80\uC99D\uD588\uB2E4.\\n\\n{/* truncate */}\\n\\n## \uC65C \uCC57\uBD07 \uD55C \uBA85\uC5D0\uAC8C \uB2E4 \uB9E1\uAE30\uBA74 \uC548 \uB418\uB294\uAC00\\n\\n\uC608\uC804 \uC5C5\uBB34\uC6A9 \uC2EC\uCE35 \uB9AC\uC11C\uCE58 1\uAC74\uC5D0 40\uBD84\uC774 \uAC78\uB838\uB2E4. \uC81C\uBBF8\uB098\uC774 \uC2EC\uCE35\uB9AC\uC11C\uCE58 10\uBD84, \uD329\uD2B8\uCCB4\uD06C\xb7\uAD50\uCC28\uAC80\uC99D 30\uBD84. 3\uAC74 \uC911 1\uAC74\uC740 \uD2C0\uB9B0 \uC815\uBCF4\uAC00 \uC11E\uC5EC \uC788\uC5C8\uB2E4.\\n\\n\uBB38\uC81C\uB294 \uBD84\uC5C5\uC758 \uBD80\uC7AC\uC600\uB2E4. \uD55C \uC5D0\uC774\uC804\uD2B8\uC5D0\uAC8C \uC804\uBD80 \uB9E1\uAE30\uBA74 \uB450 \uAC00\uC9C0 \uBCD1\uB9AC\uAC00 \uBC1C\uC0DD\uD55C\uB2E4.\\n\\n- **\uAE4A\uC774\uC758 \uD76C\uC0DD** \u2014 \uC2DC\uC7A5\uB3C4, \uC7AC\uBB34\uB3C4, \uAE30\uC220\uB3C4 \uBAA8\uB450 \uD45C\uBA74\uC801\uC73C\uB85C \uD6D1\uAC8C \uB41C\uB2E4\\n- **\uD560\uB8E8\uC2DC\uB124\uC774\uC158** \u2014 \uAC80\uC99D \uC5C6\uC774 \uC0DD\uC131\uB41C \uC22B\uC790\uAC00 \uC2AC\uCA4D \uB07C\uC5B4\uB4E0\uB2E4\\n\\n\uD574\uACB0\uCC45\uC740 \uC804\uB7B5\uCEE8\uC124\uD305 \uD38C\uC774 \uC218\uC2ED \uB144 \uC804\uC5D0 \uC774\uBBF8 \uB9CC\uB4E4\uC5B4\uB480\uB2E4. **\uBD84\uC5C5\uACFC \uAD50\uCC28\uAC80\uC99D**.\\n\\n---\\n\\n## 8\uBA85 \uC5D0\uC774\uC804\uD2B8\uD300 \uC544\uD0A4\uD14D\uCC98\\n\\n```\\n[PHASE 0]  \uC624\uCF00\uC2A4\uD2B8\uB808\uC774\uD130 \u2500\u2500\u2192 MECE \uBD84\uD574, \uD575\uC2EC \uC9C8\uBB38 \uB3C4\uCD9C\\n              \u2502\\n[PHASE 1]  \u250C\u2500\u2534\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u252C\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2510\\n           \u2502            \u2502              \u2502\\n        \uB9AC\uC11C\uCC98A        \uB9AC\uC11C\uCC98B         \uB9AC\uC11C\uCC98C\\n       \uC2DC\uC7A5/\uC0B0\uC5C5      \uAE30\uC5C5/\uC7AC\uBB34       \uAE30\uC220/\uD2B8\uB80C\uB4DC\\n        (\uC6F9\uAC80\uC0C9)      (\uC6F9\uAC80\uC0C9)        (\uC6F9\uAC80\uC0C9)\\n           \u2502            \u2502              \u2502\\n[PHASE 2]  \u2514\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u252C\u2500\u2500\u2518\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2518\\n                  \u250C\u2500\u2500\u2534\u2500\u2500\u2510\\n            \uD329\uD2B8\uCCB4\uCEE4A  \uD329\uD2B8\uCCB4\uCEE4B\\n            \uC22B\uC790 \uAC80\uC99D  \uCD9C\uCC98 \uAC80\uC99D\\n                  \u2514\u2500\u2500\u252C\u2500\u2500\u2518\\n[PHASE 3]       \uAD6C\uC131\uC791\uAC00\\n              \uD53C\uB77C\uBBF8\uB4DC \uC6D0\uCE59\uC73C\uB85C\\n              \uB9C8\uD06C\uB2E4\uC6B4 \uBCF4\uACE0\uC11C \uC791\uC131\\n                    \u2502\\n[PHASE 4]       \uAC8C\uC774\uD2B8\uD0A4\uD37C\\n             \uB85C\uC9C0\uCEEC\uC53D\uD0B9 + MECE\\n                \uCD5C\uC885 \uC2B9\uC778\\n```\\n\\n\uC5ED\uD560 8\uAC1C\uAC00 5\uAC1C \uD398\uC774\uC988\uB85C \uC21C\uC11C\uB300\uB85C \uB3CC\uC544\uAC04\uB2E4. \uD575\uC2EC\uC740 **\uB2E8\uACC4\uBCC4 \uAC80\uC99D**\uC774\uB2E4. \uB9AC\uC11C\uCC98\uAC00 \uC218\uC9D1\uD55C \uB370\uC774\uD130\uB97C \uD329\uD2B8\uCCB4\uCEE4\uAC00 \uB3C5\uB9BD\uC801\uC73C\uB85C \uAC80\uC99D\uD558\uACE0, \uAC8C\uC774\uD2B8\uD0A4\uD37C\uAC00 \uCD5C\uC885 \uB17C\uB9AC\uB97C \uC810\uAC80\uD55C\uB2E4.\\n\\n---\\n\\n## 3\uAC00\uC9C0 \uC124\uACC4 \uC6D0\uCE59\\n\\n### 1. \uD55C \uBA85\uC5D0\uAC8C \uB2E4 \uC2DC\uD0A4\uC9C0 \uC54A\uB294\uB2E4\\n\\n\uBD84\uC5C5\uC758 \uADFC\uAC70\uB294 \uC778\uC9C0 \uBD80\uD558\uB2E4. \uC2DC\uC7A5 \uBD84\uC11D\uACFC \uC7AC\uBB34 \uBD84\uC11D\uACFC \uAE30\uC220 \uBD84\uC11D\uC744 \uB3D9\uC2DC\uC5D0 \uC218\uD589\uD558\uB294 \uC5D0\uC774\uC804\uD2B8\uB294 \uAC01 \uCD95\uC758 \uAE4A\uC774\uB97C \uD76C\uC0DD\uD55C\uB2E4. \uB9AC\uC11C\uCC98 3\uBA85\uC774 \uAC01\uC790 \uC804\uBB38 \uCCB4\uD06C\uB9AC\uC2A4\uD2B8\uB97C \uAC00\uC9C0\uACE0 \uBCD1\uB82C\uB85C \uC870\uC0AC\uD55C\uB2E4.\\n\\n### 2. \uC790\uAE30\uB4E4\uB07C\uB9AC \uB2E8\uACC4\uBCC4 \uAC80\uC99D\uD55C\uB2E4\\n\\n\uD329\uD2B8\uCCB4\uCEE4\uAC00 2\uBA85\uC778 \uC774\uC720\uAC00 \uC788\uB2E4. **\uC22B\uC790\uAC00 \uB9DE\uB294\uC9C0**\uC640 **\uADF8 \uC22B\uC790\uC758 \uCD9C\uCC98\uAC00 \uC2E0\uB8B0\uD560 \uC218 \uC788\uB294\uC9C0**\uB294 \uBCC4\uAC1C\uC758 \uAC80\uC99D \uC791\uC5C5\uC774\uB2E4. \uC608\uB97C \uB4E4\uC5B4 \\"\uCFE0\uD321 \uB9E4\uCD9C 35\uC870\\"\uB294 \uB450 \uBC88 \uAC80\uC99D\uB41C\uB2E4.\\n\\n- \uD329\uD2B8\uCCB4\uCEE4 A: 35\uC870\uB77C\uB294 \uC22B\uC790 \uC790\uCCB4\uAC00 \uC815\uD655\uD55C\uAC00\\n- \uD329\uD2B8\uCCB4\uCEE4 B: \uADF8 \uC22B\uC790\uB97C \uB4B7\uBC1B\uCE68\uD558\uB294 \uCD9C\uCC98\uAC00 \uACF5\uC2E0\uB825 \uC788\uB294\uAC00\\n\\n### 3. \uCEE8\uC124\uD305 \uC0AC\uACE0\uBC95\uC73C\uB85C \uBB36\uB294\uB2E4\\n\\n\uBD84\uC5C5\uB9CC\uC73C\uB860 \uBD80\uC871\uD558\uB2E4. \uC5D0\uC774\uC804\uD2B8\uB4E4\uC774 \uAC19\uC740 \uC0AC\uACE0 \uD504\uB808\uC784\uC73C\uB85C \uC791\uB3D9\uD574\uC57C \uACB0\uACFC\uAC00 \uC815\uB3C8\uB41C\uB2E4.\\n\\n| \uD504\uB808\uC784\uC6CC\uD06C | \uC801\uC6A9 \uB2E8\uACC4 | \uC5ED\uD560 |\\n|-----------|----------|------|\\n| **MECE** | PHASE 0, 4 | \uC911\uBCF5 \uC5C6\uC774, \uBE60\uC9D0 \uC5C6\uC774 \u2014 3\uAC1C \uCD95\uC774 \uC804\uCCB4 \uC9C8\uBB38\uC744 \uCEE4\uBC84\uD558\uB294\uC9C0 \uC810\uAC80 |\\n| **\uB85C\uC9C0\uCEEC \uC53D\uD0B9** | PHASE 2, 4 | \uC22B\uC790\uAC00 \uB9DE\uB294\uC9C0\uAC00 \uC544\uB2C8\uB77C \uACB0\uB860\uC774 \uB17C\uB9AC\uC801\uC73C\uB85C \uB3C4\uCD9C\uB418\uB294\uC9C0 |\\n| **\uD53C\uB77C\uBBF8\uB4DC \uC6D0\uCE59** | PHASE 3 | \uACB0\uB860 \uBA3C\uC800, \uADFC\uAC70\uB85C \uB4B7\uBC1B\uCE68 \u2014 \uBC14\uC05C \uB3C5\uC790\uB97C \uC704\uD55C \uAD6C\uC870 |\\n\\n---\\n\\n## Claude Code \uC2A4\uD0AC\uB85C \uAD6C\uD604\\n\\n\uC774 \uC6CC\uD06C\uD50C\uB85C\uC6B0\uB97C **\uC7AC\uC0AC\uC6A9 \uAC00\uB2A5\uD55C \uC2A4\uD0AC**\uB85C \uB9CC\uB4E4\uC5C8\uB2E4.\\n\\n### \uC2A4\uD0AC \uAD6C\uC870\\n\\n```\\nresearch-agent-team/\\n\u251C\u2500\u2500 SKILL.md                      # 5\uB2E8\uACC4 \uD30C\uC774\uD504\uB77C\uC778 \uC9C0\uC2DC\uC11C\\n\u2514\u2500\u2500 references/\\n    \u2514\u2500\u2500 agent-personas.md         # \uC5D0\uC774\uC804\uD2B8 8\uBA85\uC758 \uD398\uB974\uC18C\uB098\uC640 \uCCB4\uD06C\uB9AC\uC2A4\uD2B8\\n```\\n\\n`SKILL.md`\uB294 \uD30C\uC774\uD504\uB77C\uC778 \uD750\uB984\uC744 \uB2F4\uACE0, `agent-personas.md`\uB294 \uAC01 \uC5D0\uC774\uC804\uD2B8\uC758 \uB9C8\uC778\uB4DC\uC14B\uACFC \uCCB4\uD06C\uB9AC\uC2A4\uD2B8\uB97C \uB2F4\uB294\uB2E4. **Progressive Disclosure \uC6D0\uCE59** \u2014 \uC2A4\uD0AC\uC774 \uD2B8\uB9AC\uAC70\uB420 \uB54C\uB9CC SKILL.md\uAC00 \uB85C\uB4DC\uB418\uACE0, \uD398\uB974\uC18C\uB098 \uD30C\uC77C\uC740 \uD544\uC694\uD560 \uB54C \uCC38\uC870\uB41C\uB2E4.\\n\\n### \uC2A4\uD0AC \uD2B8\uB9AC\uAC70 \uC870\uAC74\\n\\n\uC2A4\uD0AC description\uC5D0 \uBA85\uC2DC\uB41C \uD2B8\uB9AC\uAC70:\\n\\n- \uAE30\uC5C5/\uC0B0\uC5C5/\uC2DC\uC7A5/\uAE30\uC220 \uB9AC\uC11C\uCE58 \uC694\uCCAD\\n- \uBE44\uC988\uB2C8\uC2A4 \uC778\uD154\uB9AC\uC804\uC2A4 \uBCF4\uACE0\uC11C \uC791\uC131\\n- \uACBD\uC7C1 \uBD84\uC11D, \uD1B5\uACC4 \uD329\uD2B8\uCCB4\uD06C\\n- \uCEE8\uC124\uD305 \uC2A4\uD0C0\uC77C \uAD6C\uC870\uD654 \uBCF4\uACE0\uC11C \uC694\uAD6C\\n\\n---\\n\\n## \uC2E4\uC804 \uAC80\uC99D \u2014 AI \uAD11\uD1B5\uC2E0 \uAE30\uC220 \uB9AC\uC11C\uCE58\\n\\n\uC2A4\uD0AC\uC744 \uB9CC\uB4E0 \uD6C4 \uC989\uC2DC \uC2E4\uC804\uC5D0 \uD22C\uC785\uD588\uB2E4. \uC8FC\uC81C: **AI \uAD11\uD1B5\uC2E0 \uAE30\uC220 \uB9AC\uC11C\uCE58 \uBC0F \uD22C\uC790 \uC804\uB7B5**.\\n\\n### PHASE 0 \u2014 \uC624\uCF00\uC2A4\uD2B8\uB808\uC774\uD130\uC758 MECE \uBD84\uD574\\n\\n\uC624\uCF00\uC2A4\uD2B8\uB808\uC774\uD130\uAC00 5\uAC1C \uD575\uC2EC \uC9C8\uBB38\uC744 \uB3C4\uCD9C\uD558\uACE0 3\uAC1C \uCD95\uC73C\uB85C \uBC30\uBD84\uD588\uB2E4.\\n\\n```\\n\uD575\uC2EC \uC9C8\uBB38 5\uAC1C:\\n1. AI \uAD11\uD1B5\uC2E0 \uC2DC\uC7A5 \uADDC\uBAA8\xb7\uC131\uC7A5\uB960\uC740?\\n2. \uD575\uC2EC \uAE30\uC220 \uC2A4\uD0DD\uACFC \uC8FC\uC694 \uD50C\uB808\uC774\uC5B4\uB294?\\n3. \uD22C\uC790 \uAC00\uB2A5\uD55C \uC21C\uC218 \uAD11\uD1B5\uC2E0 \uC885\uBAA9\xb7ETF\uB294?\\n4. \uCD5C\uC801 \uD22C\uC790 \uAE30\uAC04\uACFC \uC9C4\uC785 \uC804\uB7B5\uC740?\\n5. \uB9AC\uC2A4\uD06C \uC694\uC778\uC740?\\n\\nMECE \uBD84\uD574:\\n\u251C\u2500\u2500 \uC2DC\uC7A5/\uC0B0\uC5C5 \uCD95: 1, 4 (\uBD80\uBD84)\\n\u251C\u2500\u2500 \uAE30\uC5C5/\uC7AC\uBB34 \uCD95: 3, 4 (\uBD80\uBD84)\\n\u2514\u2500\u2500 \uAE30\uC220/\uD2B8\uB80C\uB4DC \uCD95: 2, 5 (\uBD80\uBD84)\\n```\\n\\n### PHASE 1 \u2014 \uB9AC\uC11C\uCC98 3\uBA85 \uBCD1\uB82C \uC870\uC0AC \uACB0\uACFC\\n\\n**\uB9AC\uC11C\uCC98 A (\uC2DC\uC7A5/\uC0B0\uC5C5)**\uAC00 \uD655\uC778\uD55C \uD575\uC2EC \uC218\uCE58:\\n- AI \uB370\uC774\uD130\uC13C\uD130 \uAD11\uC778\uD130\uCEE4\uB125\uD2B8 \uC2DC\uC7A5: 2025\uB144 $3.75B \u2192 2033\uB144 $18.36B\\n- Lumentum \uC804\uB9DD: 2025\uB144 $18B TAM \u2192 2030\uB144 $90B (CAGR 40%)\\n- 800G \uB370\uC774\uD130\uCF64 \uAD11\uBAA8\uB4C8: 2025\uB144 \uCD9C\uD558\uB7C9 60% \uC131\uC7A5 \uC608\uC0C1\\n\\n**\uB9AC\uC11C\uCC98 B (\uAE30\uC5C5/\uC7AC\uBB34)**\uAC00 \uD655\uC778\uD55C \uD575\uC2EC \uB370\uC774\uD130:\\n- Lumentum(LITE): \uCD5C\uADFC \uBD84\uAE30 \uB9E4\uCD9C $665.5M (YoY +65%), \uB2E4\uC74C \uBD84\uAE30 \uAC00\uC774\uB358\uC2A4 $805M\\n- Coherent(COHR): NVIDIA $2B \uD22C\uC790, InP \uC0DD\uC0B0\uB7C9 2027\uB144\uAE4C\uC9C0 4\uBC30 \uD655\uB300\\n- Marvell(MRVL): FY2026 Q2 \uB9E4\uCD9C $2.006B (YoY +58%, \uC0AC\uC0C1 \uCD5C\uACE0\uCE58)\\n\\n**\uB9AC\uC11C\uCC98 C (\uAE30\uC220/\uD2B8\uB80C\uB4DC)**\uAC00 \uD655\uC778\uD55C \uB85C\uB4DC\uB9F5:\\n- \uD50C\uB7EC\uADF8\uC5B4\uBE14 \uD2B8\uB79C\uC2DC\uBC84 \u2192 \uC2E4\uB9AC\uCF58 \uD3EC\uD1A0\uB2C9\uC2A4 \u2192 CPO(\uCF54\uD328\uD0A4\uC9C0\uB4DC \uC635\uD2F1\uC2A4) \uC804\uD658\\n- \uC2A4\uC704\uCE58 \uC18D\uB3C4: 2025\uB144 800G \u2192 2027\uB144 1.6T \u2192 2030\uB144 3.2T\\n- NVIDIA Quantum-X \uC2A4\uC704\uCE58: 115.2 Tbps, \uC804\uB825 3.5\uBC30 \uC808\uAC10\\n\\n### PHASE 2 \u2014 \uD329\uD2B8\uCCB4\uCEE4 \uAD50\uCC28\uAC80\uC99D\\n\\n\uD329\uD2B8\uCCB4\uCEE4 B(\uCD9C\uCC98 \uAC80\uC99D)\uC758 \uC2E0\uB8B0\uB3C4 \uBD84\uB958:\\n\\n| \uCD9C\uCC98 | \uB4F1\uAE09 | \uC0AC\uC720 |\\n|------|------|------|\\n| Coherent SEC 8-K | \u2705 Primary | \uACF5\uC2DD \uACF5\uC2DC |\\n| LightCounting \uB9AC\uD3EC\uD2B8 | \u2705 Tier-1 | \uAD11\uD1B5\uC2E0 \uC804\uBB38 \uB9AC\uC11C\uCE58 \uAE30\uAD00 |\\n| KODEX ETF \uC218\uC775\uB960 | \u2705 \uD655\uC778 | \uC11C\uC6B8\uACBD\uC81C \uAE30\uC0AC + \uC6B4\uC6A9\uC0AC \uACF5\uC2DC \uAD50\uCC28 \uD655\uC778 |\\n| Seeking Alpha \uBD84\uC11D | \u26A0\uFE0F Secondary | 2\uCC28 \uBBF8\uB514\uC5B4, \uB2E8\uB3C5 \uC758\uC874 \uAE08\uC9C0 |\\n\\n### PHASE 3 \u2014 \uAD6C\uC131\uC791\uAC00\uC758 \uD53C\uB77C\uBBF8\uB4DC \uC6D0\uCE59 \uC801\uC6A9\\n\\n\uBCF4\uACE0\uC11C \uCCAB \uBB38\uC7A5\uC774 \uACB0\uB860\uC774\uB2E4:\\n\\n> \\"AI \uAD11\uD1B5\uC2E0\uC740 GPU \uD074\uB7EC\uC2A4\uD130 \uAC04 \uBCD1\uBAA9\uC744 \uD574\uC18C\uD558\uB294 \uD544\uC218 \uC778\uD504\uB77C\uB85C, 2025~2030\uB144 \uC57D 40% CAGR\uB85C \uC131\uC7A5\uD574 TAM $90B\uC5D0 \uB3C4\uB2EC\uD560 \uC804\uB9DD\uC774\uB2E4. NVIDIA\uAC00 2026\uB144 3\uC6D4 \uB2E8\uB3C5\uC73C\uB85C $6B\uB97C Lumentum\xb7Coherent\xb7Marvell\uC5D0 \uD22C\uC790\uD558\uBA74\uC11C \uAD6C\uC870\uC801 \uC5C5\uC0AC\uC774\uD074\uC774 \uACF5\uC2DD \uD655\uC778\uB410\uB2E4.\\"\\n\\n\uACB0\uB860\uC744 \uBA3C\uC800 \uC4F0\uACE0, \uB098\uBA38\uC9C0 \uC139\uC158\uC774 \uADF8 \uACB0\uB860\uC744 \uB4B7\uBC1B\uCE68\uD558\uB294 \uAD6C\uC870\uB2E4.\\n\\n### PHASE 4 \u2014 \uAC8C\uC774\uD2B8\uD0A4\uD37C \uCCB4\uD06C\uB9AC\uC2A4\uD2B8\\n\\n**\uB85C\uC9C0\uCEEC \uC53D\uD0B9 \uCCB4\uD06C:**\\n- [x] \uBAA8\uB4E0 \uACB0\uB860\uC5D0 \uAC80\uC99D\uB41C \uCD9C\uCC98 \uC874\uC7AC\\n- [x] \uB9AC\uC2A4\uD06C \uC694\uC778 \uBCC4\uB3C4 \uC139\uC158\uC73C\uB85C \uADE0\uD615 \uD655\uBCF4 (\uC5C5\uD669 \uC0AC\uC774\uD074, \uBC38\uB958\uC5D0\uC774\uC158 \uACFC\uC5F4)\\n- [x] \uC139\uC158 \uAC04 \uC0C1\uCDA9 \uB370\uC774\uD130 \uC5C6\uC74C\\n\\n**MECE \uCCB4\uD06C:**\\n- [x] \uC2DC\uC7A5/\uC7AC\uBB34/\uAE30\uC220 3\uAC1C \uCD95 \uBAA8\uB450 \uCEE4\uBC84\\n- [x] PHASE 0\uC5D0\uC11C \uB3C4\uCD9C\uD55C \uD575\uC2EC \uC9C8\uBB38 5\uAC1C \uBAA8\uB450 \uB2F5\uBCC0 \uC644\uB8CC\\n- [x] \uC139\uC158 \uAC04 \uC911\uBCF5 \uC5C6\uC74C\\n\\n\uAC8C\uC774\uD2B8\uD0A4\uD37C \uC2B9\uC778 \u2192 \uCD5C\uC885 \uBCF4\uACE0\uC11C \uCD9C\uB825.\\n\\n---\\n\\n## \uBD84\uC11D: \uBB34\uC5C7\uC774 \uB2EC\uB77C\uC84C\uB294\uAC00\\n\\n### Before vs After\\n\\n| \uAD6C\uBD84 | \uAE30\uC874 \uBC29\uC2DD | 8\uBA85 \uC5D0\uC774\uC804\uD2B8\uD300 |\\n|------|----------|--------------|\\n| \uC18C\uC694 \uC2DC\uAC04 | 40\uBD84 (\uB9AC\uC11C\uCE58 10\uBD84 + \uAC80\uC99D 30\uBD84) | 10\uBD84 \uC774\uD558 |\\n| \uD560\uB8E8\uC2DC\uB124\uC774\uC158 \uBC1C\uC0DD\uB960 | 3\uAC74 \uC911 1\uAC74 (33%) | \uD329\uD2B8\uCCB4\uCEE4 2\uC911 \uAC80\uC99D\uC73C\uB85C \uB300\uD3ED \uAC10\uC18C |\\n| \uCD9C\uCC98 \uCD94\uC801 | \uC218\uB3D9 \uC7AC\uAC80\uC0C9 \uD544\uC694 | \uC18C\uC2A4 \uD14C\uC774\uBE14 \uC790\uB3D9 \uCCA8\uBD80 |\\n| \uBCF4\uACE0\uC11C \uAD6C\uC870 | \uC989\uD765\uC801 | \uD53C\uB77C\uBBF8\uB4DC \uC6D0\uCE59\uC73C\uB85C \uC77C\uAD00 |\\n\\n### \uD575\uC2EC \uC778\uC0AC\uC774\uD2B8\\n\\n**1. \uC5ED\uD560 \uBD84\uB9AC\uAC00 \uAE4A\uC774\uB97C \uB9CC\uB4E0\uB2E4**\\n\uB9AC\uC11C\uCC98 3\uBA85\uC740 \uAC01\uC790\uC758 \uCCB4\uD06C\uB9AC\uC2A4\uD2B8\uB9CC \uCC44\uC6B4\uB2E4. \uC2DC\uC7A5 \uB9AC\uC11C\uCC98\uB294 TAM\xb7CAGR\xb7\uACBD\uC7C1\uAD6C\uB3C4\uC5D0\uB9CC \uC9D1\uC911\uD558\uACE0, \uC7AC\uBB34 \uB9AC\uC11C\uCC98\uB294 IR\xb7\uACF5\uC2DC\uC5D0\uB9CC \uC9D1\uC911\uD55C\uB2E4. \uC9D1\uC911\uC774 \uAE4A\uC774\uB97C \uB9CC\uB4E0\uB2E4.\\n\\n**2. \uD329\uD2B8\uCCB4\uCEE4 \uBD84\uB9AC\uAC00 \uC2E0\uB8B0\uB97C \uB9CC\uB4E0\uB2E4**\\n\uC22B\uC790 \uAC80\uC99D\uACFC \uCD9C\uCC98 \uAC80\uC99D\uC744 \uAC19\uC740 \uC5D0\uC774\uC804\uD2B8\uAC00 \uD558\uBA74 \uD655\uC99D \uD3B8\uD5A5\uC774 \uC0DD\uAE34\uB2E4. \uBD84\uB9AC\uB41C \uB450 \uD329\uD2B8\uCCB4\uCEE4\uAC00 \uB3C5\uB9BD\uC801\uC73C\uB85C \uC791\uB3D9\uD574\uC57C \uC9C4\uC9DC \uAD50\uCC28\uAC80\uC99D\uC774 \uB41C\uB2E4.\\n\\n**3. \uD398\uB974\uC18C\uB098\uAC00 \uC77C\uAD00\uC131\uC744 \uB9CC\uB4E0\uB2E4**\\n\uAC01 \uC5D0\uC774\uC804\uD2B8\uC5D0\uAC8C \\"McKinsey \uC5B4\uAC8C\uC774\uC9C0\uBA3C\uD2B8 \uB9E4\uB2C8\uC800\\", \\"\uC140\uC0AC\uC774\uB4DC \uC560\uB110\uB9AC\uC2A4\uD2B8\\", \\"Gartner \uAE30\uC220 \uBD84\uC11D\uAC00\\" \uAC19\uC740 \uAD6C\uCCB4\uC801 \uD398\uB974\uC18C\uB098\uB97C \uC8FC\uBA74 \uC0AC\uACE0 \uD504\uB808\uC784\uC774 \uC77C\uAD00\uB41C\uB2E4. \uB9C9\uC5F0\uD55C \\"\uC804\uBB38\uAC00\uCC98\uB7FC \uBD84\uC11D\uD574\uC918\\"\uBCF4\uB2E4 \uD6E8\uC52C \uAD6C\uCCB4\uC801\uC778 \uACB0\uACFC\uAC00 \uB098\uC628\uB2E4.\\n\\n---\\n\\n## \uC2A4\uD0AC \uD65C\uC6A9 \uBC29\uBC95\\n\\nClaude Code\uC5D0\uC11C \uC774 \uC2A4\uD0AC\uC740 \uB9AC\uC11C\uCE58 \uAD00\uB828 \uC694\uCCAD\uC774 \uB4E4\uC5B4\uC624\uBA74 \uC790\uB3D9\uC73C\uB85C \uD2B8\uB9AC\uAC70\uB41C\uB2E4.\\n\\n```\\n# \uC608\uC2DC \uC785\uB825\\n\\"\uC0BC\uC131\uC804\uC790 HBM \uC0AC\uC5C5 \uD604\uD669\uACFC SK\uD558\uC774\uB2C9\uC2A4\uC640\uC758 \uACBD\uC7C1 \uAD6C\uB3C4\uB97C \uB9AC\uC11C\uCE58\uD574\uC918\\"\\n\\"2026\uB144 \uAD6D\uB0B4 \uD074\uB77C\uC6B0\uB4DC \uC2DC\uC7A5 \uC804\uB9DD \uBCF4\uACE0\uC11C \uC791\uC131\uD574\uC918\\"\\n\\"\uC624\uD508AI vs \uC564\uD2B8\uB85C\uD53D \uAE30\uC5C5 \uBE44\uAD50 \uBD84\uC11D\uD574\uC918\\"\\n```\\n\\n\uC2A4\uD0AC\uC774 \uD2B8\uB9AC\uAC70\uB418\uBA74 \uC624\uCF00\uC2A4\uD2B8\uB808\uC774\uD130\uAC00 PHASE 0\uBD80\uD130 \uC790\uB3D9\uC73C\uB85C \uC2DC\uC791\uD55C\uB2E4. \uAC01 \uD398\uC774\uC988 \uC644\uB8CC \uC2DC \uD55C\uAD6D\uC5B4\uB85C \uC9C4\uD589 \uC0C1\uD669\uC744 \uC54C\uB824\uC900\uB2E4.\\n\\n---\\n\\n## \uACB0\uB860\\n\\n\uCC57\uBD07\uC740 \uB611\uB611\uD55C \uC778\uD134\uC774\uB2E4. \uC5D0\uC774\uC804\uD2B8\uD300\uC740 \uC804\uBB38\uAC00 \uC870\uC9C1\uC774\uB2E4. \uCC28\uC774\uB294 \uBD84\uC5C5\uACFC \uAD50\uCC28\uAC80\uC99D\uC774\uB2E4.\\n\\n\uC774 \uC2A4\uD0AC\uC758 \uD575\uC2EC \uC124\uACC4 \uACB0\uC815\uC740 \uC138 \uAC00\uC9C0\uB2E4.\\n\\n1. **\uBD84\uC5C5** \u2014 \uD55C \uC5D0\uC774\uC804\uD2B8\uC5D0\uAC8C \uBAA8\uB4E0 \uC5ED\uD560\uC744 \uC8FC\uC9C0 \uC54A\uB294\uB2E4\\n2. **\uB3C5\uB9BD \uAC80\uC99D** \u2014 \uD329\uD2B8\uCCB4\uCEE4\uB294 \uB9AC\uC11C\uCC98\uC758 \uC791\uC5C5\uC5D0 \uC758\uC874\uD558\uC9C0 \uC54A\uACE0 \uB3C5\uB9BD\uC801\uC73C\uB85C \uAC80\uC99D\uD55C\uB2E4\\n3. **\uC0AC\uACE0 \uD504\uB808\uC784** \u2014 MECE, \uB85C\uC9C0\uCEEC \uC53D\uD0B9, \uD53C\uB77C\uBBF8\uB4DC \uC6D0\uCE59\uC744 \uC5D0\uC774\uC804\uD2B8 \uD398\uB974\uC18C\uB098\uC5D0 \uB0B4\uC7AC\uD654\uD55C\uB2E4\\n\\n\uC5C5\uBB34\uC6A9 \uB9AC\uC11C\uCE58\uC5D0 \uC2DC\uAC04\uC744 \uC3DF\uACE0 \uC788\uB2E4\uBA74, \uB610\uB294 AI \uACB0\uACFC\uB97C \uB2E4\uC2DC \uAC80\uC99D\uD558\uB290\uB77C \uB354 \uC624\uB798 \uAC78\uB9AC\uB294 \uC0C1\uD669\uC774\uB77C\uBA74, 8\uBA85 \uC5D0\uC774\uC804\uD2B8\uD300\uC744 \uC368\uBCF4\uAE38 \uAD8C\uD55C\uB2E4."},{"id":"build-research-agent-skill","metadata":{"permalink":"/ai-sw-engineering/blog/build-research-agent-skill","source":"@site/blog/2026-05-08-build-research-agent-skill/index.md","title":"Claude Code \uC2A4\uD0AC \uB9CC\uB4E4\uAE30 \u2014 8\uBA85 AI \uC5D0\uC774\uC804\uD2B8 \uB9AC\uC11C\uCE58\uD300 \uC2E4\uC804 \uAD6C\uCD95","description":"\uC5C5\uBB34\uC6A9 \uB9AC\uC11C\uCE58\uB97C 40\uBD84\uC5D0\uC11C 10\uBD84\uC73C\uB85C \uB2E8\uCD95\uD55C 8\uBA85 AI \uC5D0\uC774\uC804\uD2B8\uD300\uC744 Claude Code \uC2A4\uD0AC\uB85C \uC9C1\uC811 \uB9CC\uB4DC\uB294 \uBC29\uBC95\uC744 \uB2E8\uACC4\uBCC4\uB85C \uC815\uB9AC\uD55C\uB2E4. \uC774 \uAE00\uC744 \uB530\uB77C \uD558\uBA74 \uB3D9\uC77C\uD55C \uC2A4\uD0AC\uC744 30\uBD84 \uC548\uC5D0 \uB85C\uCEEC\uC5D0\uC11C \uC0AC\uC6A9\uD560 \uC218 \uC788\uB2E4.","date":"2026-05-08T00:00:00.000Z","tags":[{"inline":false,"label":"AI \uC5D0\uC774\uC804\uD2B8","permalink":"/ai-sw-engineering/blog/tags/ai-agent","description":"AI \uC5D0\uC774\uC804\uD2B8 \uC124\uACC4 \uBC0F \uC6CC\uD06C\uD50C\uB85C\uC6B0"},{"inline":false,"label":"\uC2A4\uD0AC","permalink":"/ai-sw-engineering/blog/tags/skill","description":"Claude Code \uC2A4\uD0AC \uC81C\uC791"},{"inline":false,"label":"\uB9AC\uC11C\uCE58","permalink":"/ai-sw-engineering/blog/tags/research","description":"AI \uAE30\uBC18 \uB9AC\uC11C\uCE58 \uBC29\uBC95\uB860"},{"inline":false,"label":"\uC0DD\uC0B0\uC131","permalink":"/ai-sw-engineering/blog/tags/productivity","description":"\uC5C5\uBB34 \uC0DD\uC0B0\uC131 \uD5A5\uC0C1 \uB3C4\uAD6C\uC640 \uBC29\uBC95"}],"readingTime":8.42,"hasTruncateMarker":true,"authors":[{"name":"jeonck","title":"SW Engineer","url":"https://github.com/jeonck","page":{"permalink":"/ai-sw-engineering/blog/authors/jeonck"},"imageURL":"https://github.com/jeonck.png","key":"jeonck"}],"frontMatter":{"slug":"build-research-agent-skill","title":"Claude Code \uC2A4\uD0AC \uB9CC\uB4E4\uAE30 \u2014 8\uBA85 AI \uC5D0\uC774\uC804\uD2B8 \uB9AC\uC11C\uCE58\uD300 \uC2E4\uC804 \uAD6C\uCD95","authors":["jeonck"],"tags":["ai-agent","skill","research","productivity"]},"unlisted":false,"prevItem":{"title":"8\uBA85 AI \uC5D0\uC774\uC804\uD2B8\uD300\uC73C\uB85C \uC5C5\uBB34 \uB9AC\uC11C\uCE58 10\uBD84 \uC548\uC5D0 \uB05D\uB0B4\uAE30","permalink":"/ai-sw-engineering/blog/8-agent-research-team"}},"content":"\uC5C5\uBB34\uC6A9 \uB9AC\uC11C\uCE58\uB97C 40\uBD84\uC5D0\uC11C 10\uBD84\uC73C\uB85C \uB2E8\uCD95\uD55C **8\uBA85 AI \uC5D0\uC774\uC804\uD2B8\uD300**\uC744 Claude Code \uC2A4\uD0AC\uB85C \uC9C1\uC811 \uB9CC\uB4DC\uB294 \uBC29\uBC95\uC744 \uB2E8\uACC4\uBCC4\uB85C \uC815\uB9AC\uD55C\uB2E4. \uC774 \uAE00\uC744 \uB530\uB77C \uD558\uBA74 \uB3D9\uC77C\uD55C \uC2A4\uD0AC\uC744 30\uBD84 \uC548\uC5D0 \uB85C\uCEEC\uC5D0\uC11C \uC0AC\uC6A9\uD560 \uC218 \uC788\uB2E4.\\n\\n{/* truncate */}\\n\\n## \uBB34\uC5C7\uC744 \uB9CC\uB4DC\uB294\uAC00\\n\\nClaude Code\uC5D0\uC11C \\"~~ \uB9AC\uC11C\uCE58\uD574\uC918\\"\uB77C\uACE0 \uC785\uB825\uD558\uBA74 \uC790\uB3D9\uC73C\uB85C 8\uBA85\uC758 \uAC00\uC0C1 \uC804\uBB38\uAC00\uAC00 \uC21C\uC11C\uB300\uB85C \uC791\uB3D9\uD574 \uAC80\uC99D\uB41C \uB9C8\uD06C\uB2E4\uC6B4 \uBCF4\uACE0\uC11C\uB97C \uCD9C\uB825\uD558\uB294 **\uC7AC\uC0AC\uC6A9 \uAC00\uB2A5\uD55C \uC2A4\uD0AC**\uC744 \uB9CC\uB4E0\uB2E4.\\n\\n```\\n\uC624\uCF00\uC2A4\uD2B8\uB808\uC774\uD130 (1\uBA85)\\n  \u2514\u2500 \uB9AC\uC11C\uCC98 3\uBA85 (\uC2DC\uC7A5/\uAE30\uC5C5/\uAE30\uC220) \u2190 \uC6F9 \uAC80\uC0C9 \uD3EC\uD568\\n       \u2514\u2500 \uD329\uD2B8\uCCB4\uCEE4 2\uBA85 (\uC22B\uC790 \uAC80\uC99D/\uCD9C\uCC98 \uAC80\uC99D)\\n            \u2514\u2500 \uAD6C\uC131\uC791\uAC00 (1\uBA85) \u2190 \uD53C\uB77C\uBBF8\uB4DC \uC6D0\uCE59 \uBCF4\uACE0\uC11C\\n                 \u2514\u2500 \uAC8C\uC774\uD2B8\uD0A4\uD37C (1\uBA85) \u2190 \uB85C\uC9C0\uCEEC\uC53D\uD0B9 \uCD5C\uC885 \uAC80\uD1A0\\n```\\n\\n---\\n\\n## \uC0AC\uC804 \uC900\uBE44\\n\\nClaude Code CLI\uAC00 \uC124\uCE58\uB418\uC5B4 \uC788\uC5B4\uC57C \uD55C\uB2E4.\\n\\n```bash\\n# \uC124\uCE58 \uD655\uC778\\nclaude --version\\n```\\n\\n\uC2A4\uD0AC \uB514\uB809\uD1A0\uB9AC \uACBD\uB85C\uB97C \uD655\uC778\uD55C\uB2E4. \uAE30\uBCF8\uAC12\uC740 `~/.claude/skills/`\uB2E4.\\n\\n```bash\\nls ~/.claude/skills/\\n```\\n\\n`skill-creator` \uB514\uB809\uD1A0\uB9AC\uAC00 \uBCF4\uC774\uBA74 \uC900\uBE44 \uC644\uB8CC\uB2E4. \uC5C6\uB2E4\uBA74 Claude Code \uC124\uC815\uC5D0\uC11C \uC2A4\uD0AC \uB514\uB809\uD1A0\uB9AC\uB97C \uBA3C\uC800 \uAD6C\uC131\uD574\uC57C \uD55C\uB2E4.\\n\\n---\\n\\n## Step 1 \u2014 \uC2A4\uD0AC \uCD08\uAE30\uD654\\n\\n`skill-creator`\uC5D0 \uD3EC\uD568\uB41C `init_skill.py` \uC2A4\uD06C\uB9BD\uD2B8\uB85C \uB514\uB809\uD1A0\uB9AC \uAD6C\uC870\uB97C \uC790\uB3D9 \uC0DD\uC131\uD55C\uB2E4.\\n\\n```bash\\npython3 ~/.claude/skills/skill-creator/scripts/init_skill.py \\\\\\n  research-agent-team \\\\\\n  --path ~/.claude/skills/\\n```\\n\\n\uC131\uACF5\uD558\uBA74 \uC544\uB798\uCC98\uB7FC \uCD9C\uB825\uB41C\uB2E4.\\n\\n```\\n\u2705 Created skill directory: ~/.claude/skills/research-agent-team\\n\u2705 Created SKILL.md\\n\u2705 Created scripts/example.py\\n\u2705 Created references/api_reference.md\\n\u2705 Created assets/example_asset.txt\\n```\\n\\n\uC608\uC2DC \uD30C\uC77C\uC740 \uD544\uC694 \uC5C6\uC73C\uBBC0\uB85C \uBC14\uB85C \uC815\uB9AC\uD55C\uB2E4.\\n\\n```bash\\nrm ~/.claude/skills/research-agent-team/scripts/example.py\\nrm ~/.claude/skills/research-agent-team/references/api_reference.md\\nrm ~/.claude/skills/research-agent-team/assets/example_asset.txt\\nrmdir ~/.claude/skills/research-agent-team/scripts\\nrmdir ~/.claude/skills/research-agent-team/assets\\n```\\n\\n\uCD5C\uC885 \uB514\uB809\uD1A0\uB9AC \uAD6C\uC870:\\n\\n```\\nresearch-agent-team/\\n\u251C\u2500\u2500 SKILL.md\\n\u2514\u2500\u2500 references/\\n    \u2514\u2500\u2500 (\uBE44\uC5B4 \uC788\uC74C, \uB2E4\uC74C \uB2E8\uACC4\uC5D0\uC11C \uCC44\uC6B4\uB2E4)\\n```\\n\\n---\\n\\n## Step 2 \u2014 SKILL.md \uC791\uC131\\n\\n`SKILL.md`\uB294 \uC2A4\uD0AC\uC758 \uD575\uC2EC\uC774\uB2E4. Claude\uAC00 \uC5B8\uC81C \uC774 \uC2A4\uD0AC\uC744 \uC4F8\uC9C0(`description`), \uC5B4\uB5BB\uAC8C \uC2E4\uD589\uD560\uC9C0(\uBCF8\uBB38)\uB97C \uB2F4\uB294\uB2E4.\\n\\n`~/.claude/skills/research-agent-team/SKILL.md`\uB97C \uB2E4\uC74C \uB0B4\uC6A9\uC73C\uB85C \uC791\uC131\uD55C\uB2E4.\\n\\n```markdown\\n---\\nname: research-agent-team\\ndescription: This skill should be used when the user requests deep research on a\\n  topic, asks for a structured analysis report, or wants comprehensive investigation\\n  with fact-checking. Triggers when researching companies, industries, markets, or\\n  technologies; creating business intelligence reports; performing competitive analysis;\\n  verifying statistics with credible sources; or producing consulting-style reports.\\n  Applies MECE, Logical Thinking, and Pyramid Principle frameworks through an 8-agent\\n  virtual team pipeline: Orchestrator \u2192 3 Researchers \u2192 2 Fact-Checkers \u2192 Writer \u2192\\n  Gatekeeper. Outputs a structured Markdown report with verified sources.\\n---\\n\\n# 8-Agent Research Team\\n\\n## Overview\\n\\nSimulate an 8-member specialist research team to produce deep, fact-checked, structured\\nMarkdown research reports. The pipeline runs in 5 sequential phases: scope framing \u2192\\nparallel research \u2192 fact verification \u2192 report writing \u2192 quality gate. Load\\n`references/agent-personas.md` for detailed agent personas, thinking frameworks, and\\nsource credibility rubrics.\\n\\n## Pipeline\\n\\n### PHASE 0 \u2014 Orchestrator: Frame the Problem\\n\\nPerform MECE decomposition of the research topic:\\n- Define 3\u20135 core questions the report must answer\\n- Assign each to the correct research axis (Market / Finance / Technology)\\n- Set credibility standards: prefer primary sources over secondary\\n\\nOutput a structured brief with 3 axes and core questions, then announce:\\n> \\"PHASE 0 \uC644\uB8CC \u2014 \uB9AC\uC11C\uCC98 3\uBA85 \uBCD1\uB82C \uC870\uC0AC \uC2DC\uC791\\"\\n\\n### PHASE 1 \u2014 3 Researchers: Parallel Investigation\\n\\nRun three researchers in sequence. Each uses WebSearch for real-time data, records every\\nsource URL and publication date, and flags uncertain statistics as `[\uC694\uD655\uC778]`.\\n\\n**Researcher A \u2014 Market/Industry**\\n- Market size (TAM, CAGR, forecasts), competitive landscape, demand drivers\\n- Minimum 2 WebSearch queries\\n\\n**Researcher B \u2014 Company/Finance**\\n- Revenue, growth rates, key partnerships, hyperscaler relationships\\n- Prefer: earnings calls, SEC filings, official IR pages\\n- Minimum 2 WebSearch queries\\n\\n**Researcher C \u2014 Technology/Trends**\\n- Core tech stack, product roadmap, emerging standards, R&D investments\\n- Minimum 2 WebSearch queries\\n\\nAnnounce: \\"PHASE 1 \uC644\uB8CC \u2014 \uD329\uD2B8\uCCB4\uCEE4 \uAD50\uCC28\uAC80\uC99D \uC2DC\uC791\\"\\n\\n### PHASE 2 \u2014 2 Fact-Checkers: Cross-Verification\\n\\n**Fact-Checker A \u2014 Number Verification**\\n- Verify every key statistic against a primary or authoritative secondary source\\n- Unverifiable items: mark `[\uBBF8\uAC80\uC99D]`\\n\\n**Fact-Checker B \u2014 Source Credibility**\\n- Rate each source: \u2705 Primary | \u2705 Tier-1 Research | \u26A0\uFE0F Secondary\\n- See `references/agent-personas.md` for the full credibility rubric\\n\\nAnnounce: \\"PHASE 2 \uC644\uB8CC \u2014 \uAD6C\uC131\uC791\uAC00 \uBCF4\uACE0\uC11C \uC791\uC131 \uC2DC\uC791\\"\\n\\n### PHASE 3 \u2014 Writer: Compose the Report\\n\\nApply the Pyramid Principle \u2014 conclusion first, then supporting evidence.\\n\\nMandatory report structure:\\n1. **Executive Summary** \u2014 3\u20135 bullet conclusions with \\"so what\\"\\n2. **Section 1: Market/Industry**\\n3. **Section 2: Company/Finance**\\n4. **Section 3: Technology/Trends**\\n5. **Section 4: Investment/Strategy** (if applicable)\\n6. **Risk Factors**\\n7. **Source Table** with credibility ratings\\n\\nAnnounce: \\"PHASE 3 \uC644\uB8CC \u2014 \uAC8C\uC774\uD2B8\uD0A4\uD37C \uCD5C\uC885 \uC2B9\uC778 \uC2DC\uC791\\"\\n\\n### PHASE 4 \u2014 Gatekeeper: Quality Gate\\n\\n**Logical Thinking Check**\\n- [ ] Every conclusion backed by a verified source\\n- [ ] No logical leap between evidence and conclusion\\n- [ ] Conflicting data acknowledged and reconciled\\n\\n**MECE Check**\\n- [ ] All 3 axes (Market / Finance / Technology) covered\\n- [ ] No major overlap between sections\\n- [ ] All PHASE 0 core questions answered\\n\\nIf any item fails: return to the relevant phase, fix, then re-check.\\n\\n## Output Format\\n\\n- Language: match the user\'s language (Korean if user writes in Korean)\\n- Format: Markdown with headers, tables, bullet points\\n- Source table: always included at the end\\n\\n## Resources\\n\\nLoad `references/agent-personas.md` for detailed persona prompts, thinking frameworks,\\nand source credibility rubrics.\\n```\\n\\n---\\n\\n## Step 3 \u2014 agent-personas.md \uC791\uC131\\n\\n\uAC01 \uC5D0\uC774\uC804\uD2B8\uC758 \uD398\uB974\uC18C\uB098, \uCCB4\uD06C\uB9AC\uC2A4\uD2B8, \uCEE8\uC124\uD305 \uD504\uB808\uC784\uC6CC\uD06C\uB97C \uB2F4\uB294 \uCC38\uC870 \uD30C\uC77C\uC774\uB2E4. Claude\uAC00 \uD544\uC694\uD560 \uB54C\uB9CC \uBD88\uB7EC\uC640 \uCEE8\uD14D\uC2A4\uD2B8\uB97C \uD6A8\uC728\uC801\uC73C\uB85C \uC0AC\uC6A9\uD55C\uB2E4.\\n\\n`~/.claude/skills/research-agent-team/references/agent-personas.md`\uB97C \uC791\uC131\uD55C\uB2E4.\\n\\n```markdown\\n# Agent Personas & Consulting Frameworks\\n\\n## Agent Personas\\n\\n### Orchestrator (\uCD1D\uAD04 \uC9C0\uD718\uC790)\\n**Role:** Strategic director and task allocator\\n**Mindset:** McKinsey engagement manager \u2014 think in issues, not activities\\n\\nKey behaviors:\\n- Open every session by defining the \\"so what\\" before assigning tasks\\n- Use Issue Tree: break the main question into 3 MECE sub-questions\\n- Set quality bar: \\"Would a senior partner sign off on this?\\"\\n\\nMECE decomposition template:\\n  Main Question: [Research Topic]\\n  \u251C\u2500\u2500 Market Axis:      How big is the opportunity and who are the players?\\n  \u251C\u2500\u2500 Finance Axis:     What do the numbers say about key companies?\\n  \u2514\u2500\u2500 Technology Axis:  What is the tech roadmap and who leads it?\\n\\n### Researcher A \u2014 Market/Industry\\n**Role:** Industry analyst (Gartner/IDC style)\\n**Mindset:** Data-first, structural thinking\\n\\nResearch checklist:\\n- [ ] Market size with year and source\\n- [ ] CAGR with forecast horizon\\n- [ ] Top 3\u20135 players and positioning\\n- [ ] Key demand drivers\\n- [ ] Supply-side constraints\\n\\n### Researcher B \u2014 Company/Finance\\n**Role:** Equity research analyst (sell-side style)\\n**Mindset:** Numbers tell the story; management says what they want\\n\\nResearch checklist:\\n- [ ] Revenue (last reported quarter + YoY growth)\\n- [ ] Forward guidance\\n- [ ] Key partnerships or strategic investments\\n- [ ] Market share (if available)\\n- [ ] Risks from most recent filings\\n\\n### Researcher C \u2014 Technology/Trends\\n**Role:** Technology analyst (Forrester style)\\n**Mindset:** Technology trajectory determines who wins long-term\\n\\nResearch checklist:\\n- [ ] Current dominant technology and its limitations\\n- [ ] Next-gen technology and adoption timeline\\n- [ ] Key R&D investments and partnerships\\n- [ ] Manufacturing/supply chain readiness\\n- [ ] Standards body activity\\n\\n### Fact-Checker A \u2014 Number Verification\\n**Role:** Quantitative auditor\\n**Mindset:** Every number has a provenance; find it or flag it\\n\\nVerification rubric:\\n| Status | Meaning |\\n|--------|---------|\\n| \u2705 Confirmed | Found in a primary source |\\n| \u26A0\uFE0F Plausible | Consistent with proxies but not directly verifiable |\\n| [\uBBF8\uAC80\uC99D] | Cannot trace to a credible source \u2014 flag in report |\\n\\nCommon failure modes:\\n- Market size figures 3+ years old\\n- CAGR with no base year stated\\n- \\"Analysts expect\\" with no named analyst\\n\\n### Fact-Checker B \u2014 Source Credibility\\n**Role:** Editorial standards enforcer\\n**Mindset:** A fact from a bad source is not a fact\\n\\nSource credibility tiers:\\n| Tier | Examples | Trust Level |\\n|------|----------|-------------|\\n| \u2705 Primary | SEC filings, govt stats, company IR | Highest |\\n| \u2705 Tier-1 Research | Gartner, IDC, major investment banks | High |\\n| \u26A0\uFE0F Tier-2 Media | Reuters, Bloomberg, major dailies | Medium |\\n| \u26A0\uFE0F Tier-3 | Industry blogs, Seeking Alpha | Use with caution |\\n| \u274C Unacceptable | Anonymous, undated, unattributed | Do not use |\\n\\n### Writer (\uAD6C\uC131\uC791\uAC00)\\n**Role:** Senior consultant / report author\\n**Mindset:** The reader is a busy executive \u2014 give them the answer first\\n\\nPyramid Principle:\\n  [Conclusion / Recommendation]  \u2190 State FIRST\\n  \u251C\u2500\u2500 Supporting Argument 1\\n  \u2502   \u2514\u2500\u2500 Evidence (data + source)\\n  \u251C\u2500\u2500 Supporting Argument 2\\n  \u2502   \u2514\u2500\u2500 Evidence\\n  \u2514\u2500\u2500 Supporting Argument 3\\n      \u2514\u2500\u2500 Evidence\\n\\nStyle rules:\\n- Executive Summary: 3\u20135 bullets max, each with a \\"so what\\"\\n- Section intros: key finding in the first sentence\\n- Tables preferred over prose for comparisons\\n- Uncertain items: write [\uBBF8\uAC80\uC99D], not hedge phrases\\n\\n### Gatekeeper (\uAC8C\uC774\uD2B8\uD0A4\uD37C)\\n**Role:** Final quality assurance\\n**Mindset:** Would a skeptical CFO accept this report?\\n\\nFinal checklist:\\n- [ ] Every claim has a source\\n- [ ] Conclusions follow logically from evidence\\n- [ ] Counterarguments acknowledged\\n- [ ] No contradictions between sections\\n- [ ] Source table complete with credibility ratings\\n- [ ] [\uBBF8\uAC80\uC99D] items labeled\\n- [ ] Investment disclaimer present if financial content\\n\\n## Consulting Frameworks\\n\\n### MECE\\n- Mutually Exclusive: Research axes don\'t overlap\\n- Collectively Exhaustive: Together they fully answer the question\\nTest: \\"If we removed one axis, would we miss something important?\\"\\n\\n### Logical Thinking\\n- Deductive: All premises verified \u2192 conclusion must be true\\n- Inductive: Majority trend X \u2192 likely true (flag uncertainty)\\n- Abductive: Most plausible explanation for data points\\n\\n### Pyramid Principle (Barbara Minto)\\n1. Situation \u2014 current state (1 sentence)\\n2. Complication \u2014 what is changing?\\n3. Question \u2014 what to know or decide?\\n4. Answer \u2014 conclusion FIRST\\n5. Support \u2014 data and sources\\n```\\n\\n---\\n\\n## Step 4 \u2014 \uC720\uD6A8\uC131 \uAC80\uC0AC \uBC0F \uD328\uD0A4\uC9D5\\n\\n\uC791\uC131\uC774 \uB05D\uB098\uBA74 `package_skill.py`\uB85C \uC720\uD6A8\uC131 \uAC80\uC0AC\uC640 \uD328\uD0A4\uC9D5\uC744 \uD55C \uBC88\uC5D0 \uCC98\uB9AC\uD55C\uB2E4.\\n\\n```bash\\npython3 ~/.claude/skills/skill-creator/scripts/package_skill.py \\\\\\n  ~/.claude/skills/research-agent-team \\\\\\n  ~/.claude/skills/\\n```\\n\\n\uC815\uC0C1 \uCD9C\uB825:\\n\\n```\\n\u{1F50D} Validating skill...\\n\u2705 Skill is valid!\\n  Added: research-agent-team/SKILL.md\\n  Added: research-agent-team/references/agent-personas.md\\n\u2705 Successfully packaged skill to: ~/.claude/skills/research-agent-team.zip\\n```\\n\\n\uC624\uB958\uAC00 \uB098\uBA74 frontmatter \uD615\uC2DD\uC774\uB098 description \uAE38\uC774\uB97C \uD655\uC778\uD55C\uB2E4.\\n\\n---\\n\\n## Step 5 \u2014 \uC2A4\uD0AC \uB3D9\uC791 \uD655\uC778\\n\\nClaude Code\uB97C \uC0C8\uB85C \uC5F4\uACE0 \uB9AC\uC11C\uCE58 \uC694\uCCAD\uC744 \uC785\uB825\uD55C\uB2E4.\\n\\n```\\n\uCFE0\uD321 \uC774\uCEE4\uBA38\uC2A4 \uC0AC\uC5C5 \uD604\uD669\uACFC \uACBD\uC7C1\uC0AC \uBE44\uAD50 \uB9AC\uC11C\uCE58\uD574\uC918\\n```\\n\\n\uC2A4\uD0AC\uC774 \uC62C\uBC14\uB974\uAC8C \uB85C\uB4DC\uB418\uBA74 Claude\uAC00 \uC790\uB3D9\uC73C\uB85C PHASE 0\uBD80\uD130 \uC2DC\uC791\uD558\uBA70 \uAC01 \uB2E8\uACC4\uB97C \uC644\uB8CC\uD560 \uB54C\uB9C8\uB2E4 \uC9C4\uD589 \uC0C1\uD669\uC744 \uCD9C\uB825\uD55C\uB2E4.\\n\\n```\\nPHASE 0 \uC644\uB8CC \u2014 \uB9AC\uC11C\uCC98 3\uBA85 \uBCD1\uB82C \uC870\uC0AC \uC2DC\uC791\\nPHASE 1 \uC644\uB8CC \u2014 \uD329\uD2B8\uCCB4\uCEE4 \uAD50\uCC28\uAC80\uC99D \uC2DC\uC791\\nPHASE 2 \uC644\uB8CC \u2014 \uAD6C\uC131\uC791\uAC00 \uBCF4\uACE0\uC11C \uC791\uC131 \uC2DC\uC791\\nPHASE 3 \uC644\uB8CC \u2014 \uAC8C\uC774\uD2B8\uD0A4\uD37C \uCD5C\uC885 \uC2B9\uC778 \uC2DC\uC791\\n```\\n\\n---\\n\\n## \uCD5C\uC885 \uB514\uB809\uD1A0\uB9AC \uAD6C\uC870 \uD655\uC778\\n\\n```\\n~/.claude/skills/research-agent-team/\\n\u251C\u2500\u2500 SKILL.md                        \u2190 \uD30C\uC774\uD504\uB77C\uC778 \uC9C0\uC2DC\uC11C\\n\u251C\u2500\u2500 references/\\n\u2502   \u2514\u2500\u2500 agent-personas.md           \u2190 \uC5D0\uC774\uC804\uD2B8 \uD398\uB974\uC18C\uB098 + \uD504\uB808\uC784\uC6CC\uD06C\\n\u2514\u2500\u2500 (research-agent-team.zip)       \u2190 \uBC30\uD3EC\uC6A9 \uD328\uD0A4\uC9C0\\n```\\n\\n---\\n\\n## \uCEE4\uC2A4\uD130\uB9C8\uC774\uC9D5 \uD3EC\uC778\uD2B8\\n\\n\uAE30\uBCF8 \uC2A4\uD0AC\uC744 \uADF8\uB300\uB85C \uC368\uB3C4 \uB418\uC9C0\uB9CC, \uC5C5\uBB34 \uC131\uACA9\uC5D0 \uB530\uB77C \uB450 \uACF3\uC744 \uBC14\uAFB8\uBA74 \uD6A8\uACFC\uAC00 \uB354 \uC88B\uB2E4.\\n\\n**\uB9AC\uC11C\uCC98 3\uBA85\uC758 \uC804\uBB38 \uBD84\uC57C \uBCC0\uACBD**\\n\\n\uAE30\uBCF8\uAC12(\uC2DC\uC7A5/\uAE30\uC5C5/\uAE30\uC220)\uC774 \uB9DE\uC9C0 \uC54A\uC73C\uBA74 `SKILL.md`\uC758 PHASE 1\uC744 \uC218\uC815\uD55C\uB2E4. \uC608\uC2DC:\\n- \uBC95\uB960 \uB9AC\uC11C\uCE58: \uD310\uB840 / \uC785\uBC95 \uB3D9\uD5A5 / \uC2E4\uBB34 \uD574\uC11D\\n- HR \uB9AC\uC11C\uCE58: \uCC44\uC6A9 \uC2DC\uC7A5 / \uBCF4\uC0C1 \uBCA4\uCE58\uB9C8\uD06C / \uC870\uC9C1 \uD2B8\uB80C\uB4DC\\n- \uC815\uCC45 \uB9AC\uC11C\uCE58: \uAD6D\uB0B4 \uB3D9\uD5A5 / \uD574\uC678 \uC0AC\uB840 / \uC774\uD574\uAD00\uACC4\uC790 \uBD84\uC11D\\n\\n**\uCD9C\uCC98 \uC2E0\uB8B0\uB3C4 \uAE30\uC900 \uBCC0\uACBD**\\n\\n`references/agent-personas.md`\uC758 Source Credibility \uD14C\uC774\uBE14\uC744 \uB3C4\uBA54\uC778\uC5D0 \uB9DE\uAC8C \uC218\uC815\uD55C\uB2E4. \uC758\uD559 \uB9AC\uC11C\uCE58\uB77C\uBA74 PubMed\xb7\uCF54\uD06C\uB780 \uB9AC\uBDF0\uAC00 Tier-1\uC774 \uB418\uC5B4\uC57C \uD55C\uB2E4.\\n\\n---\\n\\n## \uC694\uC57D\\n\\n| \uB2E8\uACC4 | \uC791\uC5C5 | \uD30C\uC77C |\\n|------|------|------|\\n| 1 | \uC2A4\uD0AC \uCD08\uAE30\uD654 | `init_skill.py` \uC2E4\uD589 |\\n| 2 | \uD30C\uC774\uD504\uB77C\uC778 \uC791\uC131 | `SKILL.md` |\\n| 3 | \uC5D0\uC774\uC804\uD2B8 \uD398\uB974\uC18C\uB098 \uC791\uC131 | `references/agent-personas.md` |\\n| 4 | \uC720\uD6A8\uC131 \uAC80\uC0AC + \uD328\uD0A4\uC9D5 | `package_skill.py` \uC2E4\uD589 |\\n| 5 | \uB3D9\uC791 \uD655\uC778 | Claude Code\uC5D0\uC11C \uB9AC\uC11C\uCE58 \uC694\uCCAD |\\n\\n\uC2A4\uD0AC \uD558\uB098\uB85C \uC624\uCF00\uC2A4\uD2B8\uB808\uC774\uD130\xb7\uB9AC\uC11C\uCC98\xb7\uD329\uD2B8\uCCB4\uCEE4\xb7\uC791\uAC00\xb7\uAC8C\uC774\uD2B8\uD0A4\uD37C\uAC00 \uC790\uB3D9\uC73C\uB85C \uB3CC\uC544\uAC04\uB2E4. \uCC57\uBD07 \uD55C \uBA85\uC5D0\uAC8C \uC804\uBD80 \uB9E1\uAE30\uB294 \uBC29\uC2DD\uC73C\uB85C \uB3CC\uC544\uAC08 \uC774\uC720\uAC00 \uC5C6\uB2E4."}]}}')}}]);